import React, { useEffect, useState } from 'react'
import c from './add.module.scss'
import { Icons } from '../../assets/icons'
import { API } from '../../api'

const EditStock = ({ setActive }) => {
  /* ───────── state ───────── */
  const selected = JSON.parse(localStorage.getItem('editStock')) || []        // ← массив товаров для редактирования
  const [rows, setRows]   = useState(selected.length ? selected : [])
  const [categories, setCategories] = useState([])

  /* ───────── helpers ───────── */
  const handleChange = (idx, field, value) =>
    setRows(prev =>
      prev.map((row, i) => i === idx ? { ...row, [field]: value } : row)
    )

  /* ───────── save ───────── */
  const handleSave = async () => {
    try {
      await Promise.all(rows.map(r =>
        API.updateStock(r.id, {
          code         : r.code,
          name         : r.name,
          category_id  : r.category || null,
          quantity     : +r.quantity,
          price        : +r.price,
          price_seller : +r.price_seller
          // fixed_quantity не трогаем
        })
      ))
      alert('Товар(ы) обновлены')
      setActive(false)
      window.location.reload()
    } catch (err) {
      console.error('Ошибка при обновлении:', err)
      alert('Ошибка при обновлении')
    }
  }

  /* ───────── load categories ───────── */
  useEffect(() => {
    API.getCategories()
      .then(res => setCategories(res.data))
      .catch(e => console.error('Не удалось загрузить категории', e))
  }, [])

  if (!rows.length) return <p style={{ padding: 20 }}>Нет выбранного товара для редактирования</p>

  /* ───────── UI ───────── */
  return (
    <div className={c.addExpense}>
      <div className={c.addExpense__header}>
        <h2>Изменение товара</h2>
      </div>

      {rows.map((row, idx) => (
        <div key={idx} className={c.addExpense__form}>
          {/* код */}
          <Field label="Код" value={row.code}
                 onChange={v => handleChange(idx, 'code', v)} />

          {/* название */}
          <Field label="Наименование" value={row.name}
                 onChange={v => handleChange(idx, 'name', v)} />

          {/* категория */}
          <div className={c.addExpense__form__item}>
            <label>Категория</label>
            <select
              value={row.category || ''}
              onChange={e => handleChange(idx, 'category', e.target.value)}
            >
              <option value="">‒ выберите ‒</option>
              {categories.map(cat => (
                <option key={cat.id} value={cat.id}>{cat.name}</option>
              ))}
            </select>
          </div>

          {/* количество */}
          <Field label="Количество" type="number" value={row.quantity}
                 onChange={v => handleChange(idx, 'quantity', v)} />

          {/* цена поставщика */}
          <Field label="Цена поставщика" type="number" value={row.price_seller}
                 onChange={v => handleChange(idx, 'price_seller', v)} />

          {/* цена продажи */}
          <Field label="Цена продажи" type="number" value={row.price}
                 onChange={v => handleChange(idx, 'price', v)} />
        </div>
      ))}

      <div className={c.res}>
        <button onClick={() => setActive(false)}>Отменить</button>
        <button onClick={handleSave}>
          <img src={Icons.addGreen} alt="" /> Сохранить
        </button>
      </div>
    </div>
  )
}

/* ───────── маленький компонент поля ───────── */
const Field = ({ label, value, onChange, type = 'text' }) => (
  <div className={c.addExpense__form__item}>
    <label>{label}</label>
    <input
      type={type}
      value={value}
      onChange={e => onChange(e.target.value)}
    />
  </div>
)

export default EditStock
